+    );
+    if (duplicate) {
+      console.log(
+        chalk.yellow(
+          `A session with the same prompt is already running (${duplicate.id}). Reattach with "oracle session ${duplicate.id}" or rerun with --force to start another run.`,
+        ),
+      );
+      process.exitCode = 1;
+      return;
+    }
